1	'use strict';
2	// evidence/browser/observe.js - the PECR pre-consent OBSERVATION lane (P3 Wave-1c).
3	//
4	// WHAT THIS SEES THAT HTML CANNOT (caution.md C-039): the PECR reg.6 breach is not in the page
5	// source, it is in BEHAVIOUR - non-essential cookies written, and tracker requests fired, on first
6	// load with NOTHING clicked. This lane loads a page in a fresh browser, touches nothing, records the
7	// cookies + tracker network events that appear BEFORE any consent interaction, then accepts consent
8	// and captures again for the pre/post diff. A non-essential cookie/tracker present pre-consent is an
9	// observed breach candidate carrying the captured network event as its deterministic artifact
10	// (Constitution Rule 3). This module only OBSERVES; the breach lane (P3 Wave 2) adjudicates.
11	//
12	// FOUR structural safeguards this file is built around:
13	//   1. DEADLINE (C-040 / Rule 9): ONE outer Promise.race wraps launch -> observe -> close. The 752s
14	//      hostage incident is structurally impossible here: observe() cannot outlast deadlineMs + a
15	//      bounded force-close, whatever the browser does. Proven by observe.test.js's hanging-fake test
16	//      and the p3-browser-deadline calibration fixture.
17	//   2. OPTIONAL DEPENDENCY (C-041): Playwright is NOT a package.json dependency. It is resolved
18	//      lazily via an injected launchBrowser factory (or the lazy adapter). When unavailable, the lane
19	//      records lane:{ran:false, reason:'playwright-unavailable'} LOUDLY - never a silent nothing,
20	//      never a throw that kills a mint.
21	//   3. LINK HEALTH (C-042): a found consent/cookie-policy control is health-checked via an injected
22	//      fetch; a broken control is itself a finding (kind:'consent_control_broken').
23	//   4. LICENCE-CLEAN ORACLE (C-043): classification uses evidence/browser/oracle.js, 100% own-authored
24	//      (no NC/AGPL/ShareAlike data); its licence provenance is recorded on lane.oracle.
25	//
26	// TESTABILITY: observe() never touches a real browser or network directly. It drives an injected
27	// `launchBrowser` factory that returns a browser conforming to the small contract documented in
28	// playwright-adapter.js. node:test drives the ENTIRE logic with a scripted FAKE browser; no real
29	// Chromium runs in tests or CI (the acceptance-spec rule: live-fetch paths are dependency-injected).
30	
31	const { raceWithDeadline } = require('./deadline');
32	const { resolvePlaywrightLauncher } = require('./playwright-adapter');
33	const { isTrackerHost, classifyCookie, oracleMeta } = require('./oracle');
34	// HOST is a one-door fact (Rule 1): a hostname is read through the single parsed-host door in
35	// tools/lib/safe-fetch.js, never re-derived here and never substring-matched (GAPS host-substring).
36	const { hostOf: safeHostOf } = require('../../tools/lib/safe-fetch');
37	
38	// Every budget below is a CAP, never a floor (Rule 8): the outer race takes whichever settles first.
39	const DEFAULT_DEADLINE_MS = 45000; // total launch->close ceiling; well under the 120s mint budget
40	const DEFAULT_SETTLE_MS = 3000;    // wait for on-load tags to fire and drop cookies (cap)
41	const DEFAULT_CLOSE_MS = 5000;     // force-close ceiling
42	const DEFAULT_LINK_MS = 8000;      // consent-control link-health fetch ceiling
43	
44	// ── option normalisation ───────────────────────────────────────────────────────────────────────
45	
46	function numOr(v, d) { return Number.isFinite(v) ? v : d; }
47	function numOrNull(v) { const n = Number(v); return Number.isFinite(n) ? n : null; }
48	
49	function normaliseOpts(opts) {
50	  const o = opts || {};
51	  return {
52	    deadlineMs: numOr(o.deadlineMs, DEFAULT_DEADLINE_MS),
53	    settleMs: numOr(o.settleMs, DEFAULT_SETTLE_MS),
54	    closeMs: numOr(o.closeMs, DEFAULT_CLOSE_MS),
55	    linkMs: numOr(o.linkMs, DEFAULT_LINK_MS),
56	    now: typeof o.now === 'function' ? o.now : Date.now,
57	    launchBrowser: o.launchBrowser,
58	    fetchLink: o.fetchLink,
59	    oracle: o.oracle || { isTrackerHost, classifyCookie, oracleMeta },
60	  };
61	}
62	
63	// ── oracle indirection (an injected oracle overrides the module's own; both are licence-clean) ───
64	
65	function oracleMetaOf(cfg) {
66	  const o = cfg.oracle;
67	  return (o && typeof o.oracleMeta === 'function') ? o.oracleMeta() : oracleMeta();
68	}
69	function classify(cfg, cookie) {
70	  const o = cfg.oracle;
71	  return (o && typeof o.classifyCookie === 'function') ? o.classifyCookie(cookie) : classifyCookie(cookie);
72	}
73	function trackerHost(cfg, host) {
74	  const o = cfg.oracle;
75	  return (o && typeof o.isTrackerHost === 'function') ? o.isTrackerHost(host) : isTrackerHost(host);
76	}
77	
78	// ── lane result builders (every non-ran outcome is RECORDED, never silent - C-041/Rule 4) ────────
79	
80	function unknownControl() { return { found: false, healthy: null, url: null }; }
81	
82	function lanePlaywrightUnavailable(cfg) {
83	  return { observed: [], consentControl: unknownControl(), lane: { ran: false, reason: 'playwright-unavailable', oracle: oracleMetaOf(cfg) } };
84	}
85	function laneDeadline(elapsed, cfg) {
86	  return { observed: [], consentControl: unknownControl(), lane: { ran: false, reason: 'deadline', elapsedMs: elapsed, oracle: oracleMetaOf(cfg) } };
87	}
88	function laneError(err, elapsed, cfg) {
89	  const message = String((err && err.message) || err).slice(0, 200);
90	  return { observed: [], consentControl: unknownControl(), lane: { ran: false, reason: 'error', message, elapsedMs: elapsed, oracle: oracleMetaOf(cfg) } };
91	}
92	function laneRan(observed, consentControl, diff, cfg) {
93	  return { observed, consentControl, lane: { ran: true, reason: null, diff, oracle: oracleMetaOf(cfg) } };
94	}
95	
96	// ── host + cookie helpers ────────────────────────────────────────────────────────────────────────
97	
98	function expiryDays(expires, nowMs) {
99	  const e = Number(expires);
100	  if (!Number.isFinite(e) || e <= 0) return null;
101	  return Math.round((e * 1000 - nowMs) / 86400000);
102	}
103	
104	function nonEssentialCookies(cookies, cfg) {
105	  const out = [];
106	  for (const cookie of cookies || []) {
107	    const cls = classify(cfg, cookie);
108	    if (cls.verdict === 'non_essential') out.push({ cookie, cls });
109	  }
110	  return out;
111	}
112	
113	function uniqueHosts(trackers) {
114	  const seen = new Set();
115	  const out = [];
116	  for (const ev of trackers || []) {
117	    if (ev && ev.host && !seen.has(ev.host)) { seen.add(ev.host); out.push(ev.host); }
118	  }
119	  return out;
120	}
121	
122	function firstTrackerForHost(trackers, host) {
123	  for (const ev of trackers || []) {
124	    if (ev && ev.host === host) return ev;
125	  }
126	  return null;
127	}
128	
129	function isTrackerEvent(ev, cfg) {
130	  return Boolean(ev && ev.host) && trackerHost(cfg, ev.host);
131	}
132	
133	// ── network capture: register a pre-goto listener so on-load requests are never missed ────────────
134	
135	function attachNetworkCapture(page, cfg) {
136	  const events = [];
137	  if (typeof page.on === 'function') {
138	    page.on('request', (ev) => { if (isTrackerEvent(ev, cfg)) events.push(ev); });
139	  }
140	  return { snapshot() { return events.slice(); } };
141	}
142	
143	async function snapshotState(page, capture, cfg) {
144	  const cookies = typeof page.cookies === 'function' ? await page.cookies() : [];
145	  return { cookies: Array.isArray(cookies) ? cookies : [], trackers: capture.snapshot(), ts: cfg.now() };
146	}
147	
148	// ── observed-breach construction (Rule 3: every entry carries a deterministic artifact) ───────────
149	
150	function cookieArtifact(cookie, cls, nowMs) {
151	  return {
152	    type: 'cookie_jar_entry',
153	    // No cookie VALUE is ever stored (Rule 16: it may carry PII/secrets); name + domain + expiry only.
154	    cookie: { name: cookie.name, domain: cookie.domain, expiresDays: expiryDays(cookie.expires, nowMs) },
155	    category: cls.category || 'tracking',
156	    platform: cls.platform || null,
157	  };
158	}
159	
160	function addCookieBreaches(observed, pre, cfg) {
161	  for (const { cookie, cls } of nonEssentialCookies(pre.cookies, cfg)) {
162	    const host = cls.host || String(cookie.domain || '').replace(/^\./, '');
163	    observed.push({
164	      kind: 'cookie_pre_consent',
165	      name: cookie.name,
166	      host,
167	      essential: false,
168	      networkEvent: firstTrackerForHost(pre.trackers, host),
169	      artifact: cookieArtifact(cookie, cls, pre.ts),
170	      ts: pre.ts,
171	    });
172	  }
173	}
174	
175	function addTrackerBreaches(observed, pre) {
176	  for (const host of uniqueHosts(pre.trackers)) {
177	    const ev = firstTrackerForHost(pre.trackers, host);
178	    observed.push({
179	      kind: 'tracker_request_pre_consent',
180	      name: host,
181	      host,
182	      essential: false,
183	      networkEvent: ev,
184	      artifact: { type: 'network_request', networkEvent: ev },
185	      ts: (ev && ev.ts) || pre.ts,
186	    });
187	  }
188	}
189	
190	function addBrokenControl(observed, consentControl, cfg) {
191	  if (!consentControl.found || consentControl.healthy !== false) return;
192	  observed.push({
193	    kind: 'consent_control_broken',
194	    name: consentControl.url,
195	    host: safeHostOf(consentControl.url),
196	    essential: null,
197	    networkEvent: null,
198	    artifact: { type: 'link_health', url: consentControl.url, healthy: false },
199	    ts: cfg.now(),
200	  });
201	}
202	
203	function buildObserved(pre, consentControl, cfg) {
204	  const observed = [];
205	  addCookieBreaches(observed, pre, cfg);
206	  addTrackerBreaches(observed, pre);
207	  addBrokenControl(observed, consentControl, cfg);
208	  return observed;
209	}
210	
211	function diffSummary(pre, post, cfg) {
212	  return {
213	    preNonEssentialCookies: nonEssentialCookies(pre.cookies, cfg).length,
214	    postNonEssentialCookies: nonEssentialCookies(post.cookies, cfg).length,
215	    preTrackerHosts: uniqueHosts(pre.trackers).length,
216	    postTrackerHosts: uniqueHosts(post.trackers).length,
217	  };
218	}
219	
220	// ── consent-control link health (C-042) ──────────────────────────────────────────────────────────
221	
222	function runFetch(fetchLink, url) { return Promise.resolve().then(() => fetchLink(url)); }
223	function fetchToError(e) { return { timedOut: false, value: { ok: false, status: null, error: String((e && e.message) || e) } }; }
224	function statusBad(status) { const s = Number(status); return Number.isFinite(s) && s >= 400; }
225	
226	async function linkHealth(url, cfg) {
227	  if (typeof cfg.fetchLink !== 'function') return { healthy: null, status: null };
228	  const raced = await raceWithDeadline(runFetch(cfg.fetchLink, url), cfg.linkMs, cfg.now).catch(fetchToError);
229	  if (raced.timedOut) return { healthy: false, status: null };
230	  const res = raced.value || {};
231	  return { healthy: Boolean(res.ok) && !statusBad(res.status), status: numOrNull(res.status) };
232	}
233	
234	async function checkConsentControl(control, cfg) {
235	  if (!control || !control.found) return unknownControl();
236	  const url = control.url || null;
237	  if (!url) return { found: true, healthy: null, url: null };
238	  const health = await linkHealth(url, cfg);
239	  return { found: true, healthy: health.healthy, url };
240	}
241	
242	// ── the observation pipeline (all under the outer deadline) ───────────────────────────────────────
243	
244	async function navigateUntouched(page, url, cfg) {
245	  await page.goto(url);
246	  if (typeof page.settle === 'function') await page.settle(cfg.settleMs);
247	}
248	
249	async function safeFindControl(page) {
250	  if (typeof page.findConsentControl !== 'function') return null;
251	  return page.findConsentControl();
252	}
253	
254	async function attemptConsent(page, control) {
255	  if (!control || !control.found) return;
256	  if (typeof page.clickConsent !== 'function') return;
257	  await page.clickConsent(control);
258	}
259	
260	async function runObservation(url, cfg, launcher, holder) {
261	  const browser = await launcher();
262	  holder.browser = browser;
263	  const page = await browser.newPage();
264	  const capture = attachNetworkCapture(page, cfg);
265	  await navigateUntouched(page, url, cfg);
266	  const pre = await snapshotState(page, capture, cfg);   // BEFORE any consent interaction
267	  const control = await safeFindControl(page);
268	  const consentControl = await checkConsentControl(control, cfg);
269	  await attemptConsent(page, control);                    // injected clicker (accept)
270	  const post = await snapshotState(page, capture, cfg);   // AFTER consent, for the diff
271	  const observed = buildObserved(pre, consentControl, cfg);
272	  await browser.close();
273	  holder.browser = null;
274	  return laneRan(observed, consentControl, diffSummary(pre, post, cfg), cfg);
275	}
276	
277	// ── force-close: bounded on EVERY exit path, so a stuck browser cannot reintroduce the 752s hang ──
278	
279	async function forceClose(holder, cfg) {
280	  const browser = holder.browser;
281	  holder.browser = null;
282	  if (!browser || typeof browser.close !== 'function') return;
283	  try {
284	    await raceWithDeadline(Promise.resolve().then(() => browser.close()), cfg.closeMs, cfg.now);
285	  } catch (e) {
286	    // FAIL-OPEN JUSTIFICATION (Rule 4): a browser that will not close cannot be allowed to block the
287	    // mint; the CI/mint runner is ephemeral and reaps the process. Recorded to stderr (observable),
288	    // never silently swallowed, and never rethrown into the mint path.
289	    console.error('[evidence/browser] force-close failed (non-fatal, runner is ephemeral): ' + String((e && e.message) || e).slice(0, 160));
290	  }
291	}
292	
293	async function resolveLauncher(cfg) {
294	  if (typeof cfg.launchBrowser === 'function') return cfg.launchBrowser;
295	  return resolvePlaywrightLauncher({ now: cfg.now });
296	}
297	
298	async function observeWithLauncher(url, cfg, launcher) {
299	  const holder = { browser: null };
300	  const started = cfg.now();
301	  try {
302	    const raced = await raceWithDeadline(runObservation(url, cfg, launcher, holder), cfg.deadlineMs, cfg.now);
303	    if (raced.timedOut) return laneDeadline(raced.elapsed, cfg);
304	    return raced.value;
305	  } catch (e) {
306	    // FAIL-OPEN: a launch/observe failure is RECORDED into lane.reason='error' (laneError captures
307	    // e.message) and returned; a broken browser must degrade the mint, never throw into it (Rule 4).
308	    return laneError(e, cfg.now() - started, cfg);
309	  } finally {
310	    await forceClose(holder, cfg);
311	  }
312	}
313	
314	/**
315	 * observe(url, opts) -> Promise<bundle.browser>. Never throws, never hangs a mint.
316	 *
317	 * opts (all optional; live-fetch paths are dependency-injected):
318	 *   launchBrowser  async () => browser        the browser factory (see playwright-adapter.js contract).
319	 *                                             Absent -> the lazy real Playwright adapter is tried; if no
320	 *                                             driver resolves, lane:{ran:false, reason:'playwright-unavailable'}.
321	 *   fetchLink      async (url) => {ok,status} injected consent-control link-health fetch (C-042).
322	 *   deadlineMs     number   total launch->close ceiling (default 45000; a CAP, never a floor).
323	 *   settleMs       number   post-navigation settle (default 3000).
324	 *   closeMs        number   force-close ceiling (default 5000).
325	 *   linkMs         number   link-health fetch ceiling (default 8000).
326	 *   now            () => ms injected clock (default Date.now) for deterministic elapsed/ts in tests.
327	 *   oracle         { isTrackerHost, classifyCookie, oracleMeta }  override (default: the licence-clean module oracle).
328	 *
329	 * Returns { observed, consentControl, lane } where:
330	 *   observed[]      { kind, name, host, essential, networkEvent, artifact, ts }
331	 *                   kind in { cookie_pre_consent, tracker_request_pre_consent, consent_control_broken }.
332	 *   consentControl  { found, healthy, url }.
333	 *   lane            { ran, reason, oracle:{source,licence}, ... } - the lane's outcome, always recorded.
334	 */
335	async function observe(url, opts) {
336	  const cfg = normaliseOpts(opts);
337	  const launcher = await resolveLauncher(cfg);
338	  if (typeof launcher !== 'function') return lanePlaywrightUnavailable(cfg);
339	  return observeWithLauncher(url, cfg, launcher);
340	}
341	
342	module.exports = {
343	  observe,
344	  // exported for unit tests and the calibration fixture (never re-derives a fact; helpers only):
345	  normaliseOpts,
346	  buildObserved,
347	  diffSummary,
348	  checkConsentControl,
349	  laneDeadline,
350	  lanePlaywrightUnavailable,
351	  DEFAULT_DEADLINE_MS,
352	  DEFAULT_SETTLE_MS,
353	  DEFAULT_CLOSE_MS,
354	  DEFAULT_LINK_MS,
355	};
