1	'use strict';
2	// evidence/registers/registers.js — THE orchestrator for evidence/registers/ (P3 Wave 1b).
3	//
4	// fetchRegisters(identityHints, opts) -> the EvidenceBundle.registers object described in
5	// facts/README.md: { companiesHouse?, gleif?, sra?, cqc?, fca?, ico?, notes:[...] }. Each register
6	// key is present ONLY when its module returned a genuine, name-matched row (Constitution C-004); a
7	// missing key means "no evidence", never "checked and clean", and never a guess. notes[] carries a
8	// loud, structured entry for every register that was skipped, degraded (missing key/config, a fetch
9	// error, a timeout) or that answered with no acceptable name match (C-041 doctrine: an evidence
10	// lane's absence is visible, never silent).
11	//
12	// facts/identity.js, facts/jurisdiction.js and facts/sector.js remain PURE consumers of this bundle
13	// (Rule 1): this module produces no client-facing fact itself, only pre-fetched register rows.
14	const { lookupCompaniesHouse } = require('./companies-house');
15	const { lookupGleif } = require('./gleif');
16	const { lookupSra } = require('./sra');
17	const { lookupCqc } = require('./cqc');
18	const { lookupFca } = require('./fca');
19	const { lookupIco } = require('./ico');
20	const { domainStemFallback } = require('./lib/name-match');
21	
22	let canonicalSector = (s) => (s == null ? null : String(s));
23	try {
24	  ({ canonicalSector } = require('../../facts/vocabulary.js'));
25	} catch (_err) {
26	  // FAIL-OPEN: facts/vocabulary.js is the one door for the sector taxonomy; if it is ever absent
27	  // this module must still function (a raw, un-canonicalised sector string is a degraded but honest
28	  // input to the per-register applicability gates below, each of which already treats an
29	  // unrecognised sector as "try anyway" rather than silently skipping), so this keeps the
30	  // already-assigned identity fallback above rather than crashing module load.
31	}
32	
33	// resolveQuery(hints) -> the best company-name candidate to search registers with. A caller-supplied
34	// company-name hint always wins; otherwise this falls back to a bare domain-stem guess (a minimal,
35	// non-authoritative seed — never the identity fact itself; facts/identity.js is the one door for
36	// that, Rule 1).
37	function resolveQuery(hints) {
38	  const company = hints && typeof hints.company === 'string' ? hints.company.trim() : '';
39	  if (company) return company;
40	  return domainStemFallback(hints && hints.domain);
41	}
42	
43	// tryUkRegisters(hints) -> true unless the caller has told us the firm's country is explicitly
44	// something other than UK. An unknown/absent country hint still tries: withholding a UK register
45	// check because jurisdiction is not YET resolved would be circular — a register hit is itself
46	// Tier-A jurisdiction evidence (facts/README.md's confidence ladder), so registers must run before,
47	// not after, jurisdiction is settled.
48	function tryUkRegisters(hints) {
49	  const country = hints && hints.country ? String(hints.country).toUpperCase() : '';
50	  return !country || country === 'UK' || country === 'GB';
51	}
52	
53	function callArgs(query, hints, opts) {
54	  return {
55	    query,
56	    domain: hints && hints.domain,
57	    sector: hints && hints.sector ? canonicalSector(hints.sector) : null,
58	    fetchFn: opts.fetchFn,
59	    deadlineMs: opts.deadlineMs,
60	    keys: opts.keys || {},
61	    log: opts.log,
62	  };
63	}
64	
65	// buildLookups(query, hints, opts) -> [{key, run}], the applicable register calls for this hint set.
66	// GLEIF is worldwide and always attempted; the other five are UK-specific and gated by
67	// tryUkRegisters (each also self-gates on sector where relevant, e.g. SRA/CQC/FCA).
68	function buildLookups(query, hints, opts) {
69	  const args = callArgs(query, hints, opts);
70	  const lookups = [{ key: 'gleif', run: () => lookupGleif(args) }];
71	  if (tryUkRegisters(hints)) {
72	    lookups.push(
73	      { key: 'companiesHouse', run: () => lookupCompaniesHouse(args) },
74	      { key: 'sra', run: () => lookupSra(args) },
75	      { key: 'cqc', run: () => lookupCqc(args) },
76	      { key: 'fca', run: () => lookupFca(args) },
77	      { key: 'ico', run: () => lookupIco(args) }
78	    );
79	  }
80	  return lookups;
81	}
82	
83	// fetchRegisters(identityHints, opts) -> Promise<EvidenceBundle.registers>. `identityHints` is
84	// {domain, company?, country?, sector?}; `opts` is {fetchFn, deadlineMs?, keys?, log?}. Every
85	// applicable register is looked up IN PARALLEL (Rule 8: no serial rounds where width can widen; each
86	// call is independently deadline-bound, so total wall time is bound by the slowest single call, not
87	// their sum).
88	async function fetchRegisters(identityHints, opts) {
89	  const hints = identityHints || {};
90	  const options = opts || {};
91	  if (typeof options.fetchFn !== 'function') {
92	    throw new Error(
93	      'evidence/registers/registers.js: fetchRegisters requires opts.fetchFn (dependency-injected '
94	      + 'fetch; Rule 9 — no raw network call is ever made by this module)'
95	    );
96	  }
97	  const query = resolveQuery(hints);
98	  const lookups = buildLookups(query, hints, options);
99	  const settled = await Promise.all(lookups.map((l) => l.run().then((result) => ({ key: l.key, result }))));
100	
101	  const bundle = { notes: [] };
102	  for (const { key, result } of settled) {
103	    if (result.row) bundle[key] = result.row;
104	    if (result.note) bundle.notes.push(result.note);
105	  }
106	  return bundle;
107	}
108	
109	// ---------------------------------------------------------------------------------
110	// Calibration CLI (the earn-your-zero contract, eval/calibration-known-bad/run.js dialect).
111	// `node evidence/registers/registers.js --calibrate [--json <path>]` runs every
112	// p3-register-*.json fixture under eval/calibration-known-bad/fixtures/. Each fixture plants a
113	// non-empty, HTTP-200 register response that is NOT a real name match (C-004: the old
114	// register-check.js / register-grounding.js class); a FINDING is emitted only when this module
115	// correctly refuses to return a row for it. Zero findings means the C-004 gate is broken, and the
116	// calibration runner (run.js) fails CI.
117	// ---------------------------------------------------------------------------------
118	function fakeFetchFn(fixture) {
119	  return (url, options) => {
120	    const key = options && options.requestKey;
121	    const canned = fixture.fetchResponses && key ? fixture.fetchResponses[key] : null;
122	    return Promise.resolve(canned || null);
123	  };
124	}
125	
126	async function runOneFixture(file, fixture) {
127	  const result = await fetchRegisters(fixture.hints || {}, {
128	    fetchFn: fakeFetchFn(fixture),
129	    deadlineMs: 5000,
130	    keys: fixture.keys || {},
131	    log: () => {},
132	  });
133	  const poison = fixture.poison || {};
134	  const forbiddenRegisters = poison.forbidden_registers || [];
135	  const stillPresent = forbiddenRegisters.filter((r) => result[r] !== undefined);
136	  if (stillPresent.length > 0 || forbiddenRegisters.length === 0) return [];
137	  return [{
138	    file,
139	    line: 1,
140	    rule: 'register-nonmatch-rejected',
141	    message: 'refused the poisoned non-matching candidate for ' + forbiddenRegisters.join(', ') + '; no row returned',
142	  }];
143	}
144	
145	async function runCalibration(fixturesDir) {
146	  const fs = require('fs');
147	  const path = require('path');
