87	  for (let i = 0; i < fetchList.length; i++) {
88	    const { page, klass, truncated: t, bodyHash } = contentPageFrom(fetchList[i], results[i], cap);
89	    telemetry[klass] = (telemetry[klass] || 0) + 1;
90	    if (!page) continue;
91	    if (seenBody.has(bodyHash)) continue;
92	    seenBody.add(bodyHash);
