124	}
125	
126	// crawl(domain, opts) -> the evidence bundle. Thin orchestrator: resolve budgets, fetch the homepage,
127	// discover links + sitemap in parallel, order Tier-1-first then cap, fetch the corpus in parallel, follow
128	// footer documents, and assemble the corpus + coverage report.
129	async function crawl(domain, opts = {}) {
130	  const dom = normaliseDomain(domain);
131	  if (!dom || !dom.includes('.')) throw new Error('crawl: a fetchable domain (with a public suffix) is required, got ' + JSON.stringify(domain));
132	  if (typeof opts.fetchFn !== 'function') throw new Error('crawl: opts.fetchFn is required (all network is dependency-injected)');
133	  const log = typeof opts.log === 'function' ? opts.log : () => {};
134	  const notes = [];
135	  const record = (kind, msg) => { notes.push({ kind, msg }); log(kind, msg); };
136	
137	  const cap = typeof opts.corpusMaxChars === 'number' ? opts.corpusMaxChars : resolveCap('CORPUS_MAX_CHARS', CORPUS_CAP_DEFAULT, CORPUS_CAP_FLOOR);
138	  const maxPages = typeof opts.maxPages === 'number' ? opts.maxPages : resolveCap('MAX_CRAWL_PAGES', PAGES_DEFAULT, PAGES_FLOOR);
139	  const width = typeof opts.width === 'number' && opts.width > 0 ? opts.width : WIDTH_DEFAULT;
140	  const deadlineMs = typeof opts.deadlineMs === 'number' ? opts.deadlineMs : DEADLINE_DEFAULT;
141	  const perPageMs = Math.min(deadlineMs, opts.perPageMs || 20000);
142	  const base = 'https://' + dom;
143	  const accepted = new Set([safeFetch.registrableDomain(dom)]);
144	  const fetchXml = typeof opts.fetchXml === 'function' ? opts.fetchXml : makeFetchXml(opts.fetchFn, perPageMs, opts.timers);
145	
146	  const home = await fetchPage(opts.fetchFn, base + '/', perPageMs, opts.timers);
147	  const homeHtml = home && home.body ? String(home.body) : '';
148	  const homeKlass = extract.pageContentClass(home ? home.status : 0, homeHtml);
149	  if (homeKlass !== 'content') record('homepage-not-content', base + '/ classified as "' + homeKlass + '"; no content asserted from it (C-031/C-038)');
150	
151	  const [links, sitemap] = await Promise.all([
152	    Promise.resolve(homeHtml ? discover.discoverLinks(homeHtml, base, accepted) : []),
153	    discover.discoverSitemap(dom, accepted, fetchXml).catch(() => []),
154	  ]);
155	  const fetchList = discover.orderCandidates(base + '/', [...links, ...sitemap], accepted, maxPages);
156	
157	  const homeUrl = base + '/';
158	  const results = await runPool(fetchList, width, deadlineMs,
159	    (u) => (u === homeUrl ? Promise.resolve(home) : fetchPage(opts.fetchFn, u, perPageMs, opts.timers)), opts.now);
160	  const { pages, truncated, telemetry } = accumulateCorpus(fetchList, results, cap);
161	  if (truncated) record('corpus-truncated', 'a page exceeded the ' + cap + '-char corpus cap; absence claims on it demote to needs-review (C-024)');
162	
163	  const footerText = extract.extractFooterText(homeHtml);
164	  let docResult = { documents: [], unparsed: [], unparsedClasses: new Set(), notes: [] };
165	  if (opts.followDocuments !== false && pages.length) {
166	    docResult = await collectDocuments(footerLinks(homeHtml, base, accepted),
167	      { fetchFn: opts.fetchFn, deadlineMs: perPageMs, timers: opts.timers, log: record });
168	  }
169	
170	  const unreachable = pages.length === 0;
171	  const reason = blockReason(home, homeKlass, pages.length);
172	  const corpus = { pages, footerText: footerText || undefined };
173	  return {
174	    domain: dom,
175	    corpus,
176	    unreachable,
177	    reason,
178	    documents: { records: docResult.documents, unparsed: docResult.unparsed },
179	    coverage: buildCoverage(pages, opts, truncated, docResult.unparsedClasses),
180	    telemetry: { ...telemetry, pages_captured: pages.length, truncated, via: unreachable ? 'none' : 'direct' },
181	    notes,
182	  };
183	}
184	
185	module.exports = { crawl, resolveCap, normaliseDomain, accumulateCorpus, contentPageFrom, footerLinks, blockReason };
