208	function runExternalChecker(checkerPath) {
209	  const jsonOut = path.join(fs.mkdtempSync(path.join(os.tmpdir(), 'calibrate-')), 'findings.json');
210	  const stdout = runCalibrateProcess(checkerPath, jsonOut);
211	  if (fs.existsSync(jsonOut)) {
212	    const fromFile = findingsFromParsed(JSON.parse(fs.readFileSync(jsonOut, 'utf8')));
213	    if (fromFile) return fromFile;
214	  }
215	  const fromStdout = findingsFromParsed(safeJsonParse(stdout));
216	  if (fromStdout) return fromStdout;
217	  throw new Error('checker emitted neither {findings:[]} JSON on stdout nor a findings JSON file via --json');
218	}
