243	// spawning an external checker.
244	function runInternalCalibration(cal, fixtureAbs) {
245	  const entries = [];
246	  let failed = 0;
247	  try {
248	    const findings = runInternalPayloadContract(fixtureAbs[0]);
249	    if (findings.length > 0) {
250	      entries.push({ name: cal.name, status: 'PASS', detail: `${findings.length} finding(s) on the fixture (e.g. ${findings[0].message})` });
251	    } else {
252	      entries.push({ name: cal.name, status: 'FAIL', detail: 'validatePayload() returned an EMPTY missing list on a deliberately incomplete payload - the contract gate is broken' });
253	      failed++;
254	    }
255	  } catch (e) {
256	    entries.push({ name: cal.name, status: 'FAIL', detail: `internal check errored: ${e.message}` });
257	    failed++;
258	  }
259	  return { entries, failed, skipped: 0 };
260	}
