262	// missingCheckerResult(cal, strict) -> the {entries,failed,skipped} result when no checker under
263	// tools/ was found for this calibration: FAIL in --strict mode (a fixture without a live checker
264	// is an unearned zero), SKIPPED otherwise (tools/ agent has not landed this gate yet).
265	function missingCheckerResult(cal, strict) {
266	  const detail = `no checker found (looked at: ${cal.checkerCandidates.join(', ')})`;
267	  if (strict) {
268	    return { entries: [{ name: cal.name, status: 'FAIL', detail: `${detail} - strict mode: a fixture without a live checker is an unearned zero` }], failed: 1, skipped: 0 };
269	  }
270	  return { entries: [{ name: cal.name, status: 'SKIPPED', detail: `${detail} - tools/ agent has not landed this gate yet; CI must flip to --strict when it does` }], failed: 0, skipped: 1 };
271	}
272	
273	// judgeCheckerFindings(cal, checker) -> {entries, failed} from running the checker and confirming
274	// EVERY fixture listed for this calibration was caught (CR-38: a multi-fixture calibration
275	// previously passed as long as ONE fixture produced a finding, so a checker could keep catching an
276	// old fixture while missing a new one).
277	function judgeCheckerFindings(cal, checker) {
278	  const findings = runExternalChecker(checker);
279	  const missingFixtures = cal.fixtures.filter((fx) => !findings.some((fd) => String(fd.file || '').includes(fx)));
280	  const fixtureHits = findings.filter((fd) => cal.fixtures.some((fx) => String(fd.file || '').includes(fx)));
281	  if (missingFixtures.length === 0) {
282	    return { entries: [{ name: cal.name, status: 'PASS', detail: `${fixtureHits.length} finding(s) across all ${cal.fixtures.length} fixture(s) via ${path.relative(REPO_ROOT, checker)}` }], failed: 0 };
283	  }
284	  return { entries: [{ name: cal.name, status: 'FAIL', detail: `${path.relative(REPO_ROOT, checker)} reported ZERO findings on: ${missingFixtures.join(', ')} - it has not earned its zero on every seeded fixture (${cal.description})` }], failed: 1 };
285	}
286	
287	// runExternalCalibration(cal, strict) -> {entries, failed, skipped}. Locates the checker under
288	// tools/ via findChecker(), reports SKIPPED (or FAIL in --strict mode) if none is found yet, and
289	// otherwise runs its --calibrate contract via runExternalChecker() and checks every listed
290	// fixture was caught. Behaviour is unchanged from the original inline version: failed/skipped are
291	// still exactly 0 or 1 per call (missingCheckerResult and judgeCheckerFindings each push exactly
292	// one entry and increment their own counter by at most 1).
293	function runExternalCalibration(cal, strict) {
294	  const checker = findChecker(cal.checkerCandidates);
295	  if (!checker) return missingCheckerResult(cal, strict);
296	  try {
297	    const { entries, failed } = judgeCheckerFindings(cal, checker);
298	    return { entries, failed, skipped: 0 };
299	  } catch (e) {
300	    return { entries: [{ name: cal.name, status: 'FAIL', detail: `checker errored or broke the --calibrate contract: ${e.message}` }], failed: 1, skipped: 0 };
301	  }
302	}
303	
304	// runOneCalibration(cal, strict) -> {entries: [...], failed: N, skipped: N} for one CALIBRATIONS
305	// entry. Semantics are UNCHANGED from the original inline loop body (do not change the
306	// CALIBRATIONS registry semantics or --strict behaviour): missing fixture files short-circuit
307	// straight to a FAIL entry per file; otherwise an "internal" calibration runs payload/contract
308	// directly and everything else runs its checker's --calibrate contract. The original loop tested
309	// `results.some((r) => r.name === cal.name && r.status === 'FAIL')` against the GLOBAL results
310	// list; since every entry pushed for earlier calibrations carries a DIFFERENT cal.name, that was
311	// already equivalent to testing only the entries just pushed for THIS calibration, which is what
312	// checkMissingFixtures's own (per-calibration) entries list does directly.
313	function runOneCalibration(cal, strict) {
314	  const fixtureAbs = cal.fixtures.map((f) => path.join(FIXTURES_DIR, f));
315	  const missing = checkMissingFixtures(cal, fixtureAbs);
316	  if (missing.entries.length > 0) return missing;
317	  if (cal.internal) return runInternalCalibration(cal, fixtureAbs);
318	  return runExternalCalibration(cal, strict);
319	}
320	
321	// report({strict, results, failed, skipped, asJson}) -> prints the run's summary in --json or
322	// human form, unchanged from the original inline block in main() (params bundled into one object;
323	// not exported, so the call site below is the only caller to update).
324	function report({ strict, results, failed, skipped, asJson }) {
325	  if (asJson) {
326	    console.log(JSON.stringify({ strict, results, failed, skipped }, null, 2));
327	    return;
328	  }
329	  console.log('calibration-known-bad: the earn-your-zero gate');
330	  for (const r of results) console.log(`  ${r.status.padEnd(7)} ${r.name}: ${r.detail}`);
331	  if (failed > 0) {
332	    console.log(`RESULT: FAIL - ${failed} gate(s) did not catch their seeded known-bad fixture. A gate that misses planted disease is reporting worthless greens.`);
333	  } else if (skipped > 0) {
334	    console.log(`RESULT: OK with ${skipped} SKIPPED - external checkers not landed yet. Flip CI to --strict once tools/ lands.`);
335	  } else {
336	    console.log('RESULT: OK - every gate caught its fixture.');
337	  }
338	}
339	
340	function main(argv) {
341	  const args = argv.slice(2);
342	  const strict = args.includes('--strict');
343	  const asJson = args.includes('--json');
344	  const unknown = args.filter((a) => !['--strict', '--json'].includes(a));
345	  if (unknown.length) {
346	    console.error(`Unknown argument(s): ${unknown.join(', ')}`);
347	    return 2;
348	  }
349	
350	  const results = [];
351	  let failed = 0;
352	  let skipped = 0;
353	
354	  for (const cal of CALIBRATIONS) {
355	    const r = runOneCalibration(cal, strict);
356	    results.push(...r.entries);
357	    failed += r.failed;
358	    skipped += r.skipped;
359	  }
360	
361	  report({ strict, results, failed, skipped, asJson });
362	  return failed > 0 ? 1 : 0;
363	}
364	
365	if (require.main === module) {
366	  process.exit(main(process.argv));
367	}
368	
369	module.exports = { CALIBRATIONS, runExternalChecker };
