712	// Calibration CLI (the earn-your-zero contract in eval/calibration-known-bad/run.js).
713	// `node facts/identity.js --calibrate [--json <path>]` runs every p1-identity-*.json
714	// fixture. Each fixture plants a poisoned candidate; a FINDING is emitted only when
715	// the module correctly refuses the poison. Zero findings means the rejection gate is
716	// broken, and the calibration runner fails CI.
717	// ---------------------------------------------------------------------------------
718	function runCalibration(fixturesDir) {
719	  const fs = require('fs');
720	  const path = require('path');
721	  const dir = fixturesDir
722	    || path.join(__dirname, '..', 'eval', 'calibration-known-bad', 'fixtures');
723	  const findings = [];
724	  const files = fs.readdirSync(dir).filter((f) => /^p1-identity-.*\.json$/.test(f)).sort();
725	  for (const f of files) {
726	    // Fail closed on an unsafe path component before it ever reaches path.join (traversal
727	    // guard); every fixture name comes from the already-filtered p1-identity-*.json glob above,
728	    // so this never fires in practice.
729	    if (!/^[a-z0-9][a-z0-9.-]{0,251}$/i.test(f)) {
730	      throw new Error('unsafe path component: ' + JSON.stringify(f));
731	    }
732	    const abs = path.join(dir, f);
733	    const fixture = JSON.parse(fs.readFileSync(abs, 'utf8'));
734	    const poison = fixture.poison || {};
735	    const result = resolveIdentity(fixture.bundle);
736	    const emittedName = result.display_name.value;
737	    const emittedSlug = result.slug.value;
738	    const forbiddenNames = [].concat(poison.display_name_forbidden || []);
739	    const forbiddenSlugs = [].concat(poison.slug_forbidden || []);
740	    const namePoisoned = forbiddenNames.some(
741	      (n) => emittedName && normName(emittedName) === normName(n)
742	    );
743	    const slugPoisoned = forbiddenSlugs.some((s) => emittedSlug === s);
744	    if (!namePoisoned && !slugPoisoned) {
745	      findings.push({
746	        file: abs,
747	        line: 1,
748	        rule: 'identity-poison-rejected',
749	        message: 'refused poisoned candidate '
750	          + JSON.stringify(forbiddenNames[0] || forbiddenSlugs[0] || '(none)')
751	          + '; resolved display_name=' + JSON.stringify(emittedName)
752	          + ' (' + result.display_name.confidence + '), slug=' + JSON.stringify(emittedSlug),
753	      });
754	    }
755	    // A poisoned emission produces NO finding for this fixture: the calibration
756	    // runner then fails, which is exactly the earn-your-zero contract.
757	  }
758	  return findings;
759	}
760	
761	function calibrateMain(argv) {
762	  const fs = require('fs');
763	  const args = argv.slice(2);
764	  const jsonIdx = args.indexOf('--json');
765	  const jsonPath = jsonIdx !== -1 ? args[jsonIdx + 1] : null;
766	  const findings = runCalibration();
767	  if (jsonPath) fs.writeFileSync(jsonPath, JSON.stringify(findings, null, 2));
768	  process.stdout.write(JSON.stringify({ checker: 'identity', findings }) + '\n');
769	  return 0;
770	}
771	
772	if (require.main === module) {
773	  if (process.argv.includes('--calibrate')) {
774	    process.exit(calibrateMain(process.argv));
775	  } else {
776	    console.error('facts/identity.js is a library. Only --calibrate is runnable from the CLI.');
777	    process.exit(2);
778	  }
