27	const fs = require('fs');
28	const path = require('path');
29	
30	const { runGateCli, ROOT } = require('../lib/gate-cli');
31	
32	const SCAN_DIRS = ['catalogue', 'evidence', 'facts', 'applicability', 'breach', 'llm', 'payload', 'mint', 'render-proof', 'tools'];
33	
34	const RECORDER = /\b(?:_warn|warn|_record|record[A-Z_]\w*|addWarning|logWarning|manifest\.[A-Za-z_$]*(?:record|add|warn|note)\w*|logger?\.(?:warn|error)|console\.(?:warn|error)|log\.(?:warn|error)|report(?:Error|Failure|Warning)\w*|captureException)\s*\(/;
35	const JUSTIFY = /FAIL-OPEN:/;
36	
37	let acorn = null;
38	try { acorn = require('acorn'); }
39	catch (e) { acorn = null; /* FAIL-OPEN: acorn is an optional devDependency; the regex fallback below is the guaranteed engine and the self-test proves it works. */ }
40	// CI runs the self-test against BOTH engines: SWALLOW_GATE_ENGINE=regex forces the fallback even when acorn
41	// is installed, so the fallback can never rot unnoticed.
42	if (process.env.SWALLOW_GATE_ENGINE === 'regex') acorn = null;
43	
44	// ── fallback engine: comment/string-aware scan for catch blocks ─────────────────────────────────────────────
45	
46	// Walk the source character by character, tracking string/template/comment context, and return the index just
47	// past the matching close brace for the brace at `openIdx`.
48	function matchBrace(src, openIdx) {
49	  let depth = 0;
50	  let i = openIdx;
51	  while (i < src.length) {
52	    const c = src[i];
53	    const next = src[i + 1];
54	    if (c === '/' && next === '/') { const nl = src.indexOf('\n', i); i = nl === -1 ? src.length : nl + 1; continue; }
55	    if (c === '/' && next === '*') { const end = src.indexOf('*/', i + 2); i = end === -1 ? src.length : end + 2; continue; }
56	    if (c === '\'' || c === '"' || c === '`') {
57	      const q = c;
58	      i++;
59	      while (i < src.length && src[i] !== q) { if (src[i] === '\\') i++; i++; }
60	      i++;
61	      continue;
62	    }
63	    if (c === '{') depth++;
64	    if (c === '}') { depth--; if (depth === 0) return i + 1; }
65	    i++;
66	  }
67	  return src.length;
68	}
69	
70	// Find every catch clause with the fallback engine. Returns [{start, bodyStart, bodyEnd, line}].
71	function findCatchesRegex(src) {
72	  const out = [];
73	  const rx = /\bcatch\b\s*(\([^)]*\))?\s*\{/g;
74	  let m;
75	  while ((m = rx.exec(src)) !== null) {
