95	      const q = c;
96	      i++;
97	      while (i < src.length && src[i] !== q) { if (src[i] === '\\') i++; i++; }
98	      if (i >= idx) return true;
99	      i++;
100	      continue;
101	    }
102	    i++;
103	  }
104	  return false;
105	}
106	
107	// ── acorn engine ────────────────────────────────────────────────────────────────────────────────────────────
108	
109	function findCatchesAcorn(src) {
110	  const ast = acorn.parse(src, { ecmaVersion: 'latest', allowHashBang: true, allowReturnOutsideFunction: true, allowAwaitOutsideFunction: true, locations: true });
111	  const out = [];
112	  (function walk(n) {
113	    if (!n || typeof n !== 'object') return;
114	    if (n.type === 'CatchClause') out.push({ start: n.start, bodyStart: n.body.start + 1, bodyEnd: n.body.end - 1, line: n.loc.start.line });
115	    for (const k of Object.keys(n)) {
116	      const v = n[k];
117	      if (Array.isArray(v)) v.forEach(walk);
118	      else if (v && typeof v.type === 'string') walk(v);
119	    }
120	  })(ast);
121	  return out;
122	}
123	
124	// ── shared judgement ────────────────────────────────────────────────────────────────────────────────────────
125	
126	function judgeCatch(src, c) {
127	  const body = src.slice(c.bodyStart, c.bodyEnd);
128	  // Justification may sit inside the body or on the two lines immediately above the catch.
129	  const before = src.slice(Math.max(0, src.lastIndexOf('\n', Math.max(0, src.lastIndexOf('\n', c.start - 1) - 1))), c.start);
130	  if (JUSTIFY.test(body) || JUSTIFY.test(before)) return null;
131	  if (/\bthrow\b/.test(body)) return null;
132	  if (RECORDER.test(body)) return null;
133	  const bare = body.replace(/\/\/[^\n]*|\/\*[\s\S]*?\*\//g, '').trim() === '';
134	  return {
135	    line: c.line,
136	    kind: bare ? 'bare-swallow' : 'silent-swallow',
137	    excerpt: ('catch ' + body.trim()).replace(/\s+/g, ' ').slice(0, 120),
138	  };
139	}
140	
141	function scanContent(src) {
142	  let catches;
143	  let engine;
144	  if (acorn) {
145	    try { catches = findCatchesAcorn(src); engine = 'acorn'; }
146	    catch (e) { throw new Error('acorn cannot parse this file: ' + e.message + ' (a parse failure is NOT zero catches)'); }
147	  } else {
148	    catches = findCatchesRegex(src);
149	    engine = 'regex-fallback';
150	  }
151	  const violations = [];
152	  for (const c of catches) {
153	    const v = judgeCatch(src, c);
154	    if (v) violations.push(v);
155	  }
156	  return { violations, catches: catches.length, engine };
157	}
158	
159	const { listJsFiles } = require('../lib/fswalk');
160	
161	function scanTree(dirs) {
162	  const violations = [];
163	  let scanned = 0;
164	  let catches = 0;
165	  for (const dir of dirs) {
166	    for (const abs of listJsFiles(path.join(ROOT, dir))) {
167	      scanned++;
168	      const rel = path.relative(ROOT, abs).replace(/\\/g, '/');
169	      const r = scanContent(fs.readFileSync(abs, 'utf8'));
