'use strict';
/**
 * breach/verifiers/result.js - the shared result envelope and rejection-reason taxonomy every
 * verifier in this directory returns (Constitution Rule 3 / Rule 12 Gate 2).
 *
 * Every verify function in breach/verifiers/ returns exactly {verified, code, reason}:
 *   verified   boolean. true only when a deterministic artifact check passed.
 *   code       a closed, machine-readable taxonomy value (below). Stable across releases; the
 *              adjudicator and any future dashboard may switch on it.
 *   reason     a human-readable string explaining the code (never null, always present).
 *
 * CODES is deliberately flat and exhaustive: every rejection this directory can produce has exactly
 * one code, so "why was this candidate rejected" is always answerable without reading prose.
 */

const CODES = Object.freeze({
  // dispatch-level (breach/verifiers/quote-match.js's verifyCandidate)
  INVALID_CANDIDATE: 'invalid_candidate',
  MISSING_ARTIFACT: 'missing_artifact',
  UNKNOWN_ARTIFACT_TYPE: 'unknown_artifact_type',

  // quote artifacts (breach/verifiers/quote-match.js)
  QUOTE_VERIFIED: 'quote_verified',
  QUOTE_MISSING_FIELDS: 'quote_missing_fields',
  QUOTE_INVALID_SURFACE: 'quote_invalid_surface',
  QUOTE_PAGE_NOT_FOUND: 'quote_page_not_found',
  QUOTE_SURFACE_UNAVAILABLE: 'quote_surface_unavailable',
  QUOTE_MISMATCH: 'quote_mismatch',

  // network_event artifacts (breach/verifiers/network-event.js)
  NETWORK_EVENT_VERIFIED: 'network_event_verified',
  NETWORK_EVENT_MISSING_FIELDS: 'network_event_missing_fields',
  NETWORK_EVENT_LANE_NOT_RUN: 'network_event_lane_not_run',
  NETWORK_EVENT_NOT_FOUND: 'network_event_not_found',

  // register_row artifacts (breach/verifiers/register-row.js)
  REGISTER_ROW_VERIFIED: 'register_row_verified',
  REGISTER_ROW_MISSING_FIELDS: 'register_row_missing_fields',
  REGISTER_ROW_ABSENT: 'register_row_absent',
  REGISTER_ROW_MISMATCH: 'register_row_mismatch',

  // coverage_proof artifacts (breach/verifiers/coverage-proof.js)
  COVERAGE_PROOF_VERIFIED: 'coverage_proof_verified',
  COVERAGE_PROOF_MISSING_FIELDS: 'coverage_proof_missing_fields',
  COVERAGE_PROOF_NO_PAGES: 'coverage_proof_no_pages',
  COVERAGE_PROOF_PAGES_NOT_IN_BUNDLE: 'coverage_proof_pages_not_in_bundle',
  COVERAGE_PROOF_TIER1_NOT_FETCHED: 'coverage_proof_tier1_not_fetched',
  COVERAGE_PROOF_TRUNCATED: 'coverage_proof_truncated',
});

// accepted(code, reason) -> {verified:true, code, reason}. A verifier calls this ONLY when a
// deterministic artifact check has actually passed against the bundle (never on trust).
function accepted(code, reason) {
  return { verified: true, code, reason };
}

// rejected(code, reason) -> {verified:false, code, reason}. Every rejection carries a code from
// CODES above and a human-readable reason; there is no "silently drop" path in this directory.
function rejected(code, reason) {
  return { verified: false, code, reason };
}

module.exports = { CODES, accepted, rejected };

'use strict';
/**
 * breach/verifiers/network-event.js - verifies a `network_event` artifact (Constitution Rule 3:
 * "a captured network event" is one of the four things a breach finding may carry as its
 * deterministic artifact).
 *
 * Contract (candidate.artifact when type === 'network_event'):
 *   { type: 'network_event', kind, host, name, ts? }
 *
 * `kind`, `host` and `name` mirror the identifying fields of an entry in the PECR pre-consent lane's
 * own output shape, evidence/browser/observe.js's `bundle.browser.observed[]`:
 *   { kind, name, host, essential, networkEvent, artifact, ts }
 * (kind in cookie_pre_consent | tracker_request_pre_consent | consent_control_broken).
 *
 * verifyNetworkEvent never re-derives tracker/cookie classification (that stays evidence/browser's
 * one door, caution.md C-043's licence-clean oracle): it only proves the candidate's cited event is
 * an event the browser lane ACTUALLY observed, by exact field match against bundle.browser.observed.
 * A candidate citing a host/name/kind combination the lane never saw is a fabricated artifact and is
 * rejected (fail closed); it is never accepted on the strength of the claim alone.
 */
const { CODES, accepted, rejected } = require('./result');

function isNonEmptyString(v) {
  return typeof v === 'string' && v.length > 0;
}

// entryMatches(entry, artifact) -> true when one bundle.browser.observed[] entry is the exact event
// the candidate cites: same kind, same host, same name, and (when the candidate pins a timestamp)
// the same ts. This is an EQUALITY check throughout, never a substring/includes test (GAPS.md
// host-substring: a host is compared by parsed/exact identity here, never by token or substring).
function entryMatches(entry, artifact) {
  if (!entry || typeof entry !== 'object') return false;
  if (entry.kind !== artifact.kind) return false;
  if (entry.host !== artifact.host) return false;
  if (entry.name !== artifact.name) return false;
  if (artifact.ts !== undefined && entry.ts !== artifact.ts) return false;
  return true;
}

// verifyNetworkEvent(artifact, bundle) -> {verified, code, reason}. Fails closed on: missing
// identifying fields, a browser lane that never ran (nothing to verify against - C-041's "absence is
// visible, never silent" means an un-run lane cannot silently back-fill a claim either), or a cited
// event with no match in bundle.browser.observed (fabricated network event).
function verifyNetworkEvent(artifact, bundle) {
  if (!isNonEmptyString(artifact.kind) || !isNonEmptyString(artifact.host) || !isNonEmptyString(artifact.name)) {
    return rejected(
      CODES.NETWORK_EVENT_MISSING_FIELDS,
      'artifact.kind, artifact.host and artifact.name are all required to identify a network_event candidate'
    );
  }
  const browser = bundle && bundle.browser;
  if (!browser || !browser.lane || browser.lane.ran !== true) {
    return rejected(
      CODES.NETWORK_EVENT_LANE_NOT_RUN,
      'bundle.browser.lane did not run (ran !== true); there is no observation to verify a network_event against'
    );
  }
  const observed = Array.isArray(browser.observed) ? browser.observed : [];
  const found = observed.some((entry) => entryMatches(entry, artifact));
  if (!found) {
    return rejected(
      CODES.NETWORK_EVENT_NOT_FOUND,
      'no entry in bundle.browser.observed matches kind=' + JSON.stringify(artifact.kind)
        + ' host=' + JSON.stringify(artifact.host) + ' name=' + JSON.stringify(artifact.name)
    );
  }
  return accepted(CODES.NETWORK_EVENT_VERIFIED, 'matched an entry in bundle.browser.observed');
}

module.exports = { verifyNetworkEvent, entryMatches };

'use strict';
/**
 * breach/verifiers/register-row.js - verifies a `register_row` artifact (Constitution Rule 3: "a
 * register row" is one of the four things a breach finding may carry as its deterministic artifact).
 *
 * Contract (candidate.artifact when type === 'register_row'):
 *   { type: 'register_row', register: 'companiesHouse'|'gleif'|'sra'|'cqc'|'fca'|'ico', row: {...} }
 *
 * `register` names the key on EvidenceBundle.registers (facts/README.md); `row` is the EXACT row
 * object the candidate is citing as its evidence, copied verbatim from what the candidate read off
 * the bundle. verifyRegisterRow does not re-run the name-match gate (caution.md C-004: that is
 * evidence/registers/'s one door, already applied before the row ever reached the bundle) - it proves
 * only that the cited row is not a paraphrase or an invention: it deep-equals the row actually present
 * on bundle.registers[register]. This directory never hardcodes the six register keys itself (that
 * enumeration belongs to evidence/registers/registers.js, Rule 1's one-door doctrine): an unknown or
 * misspelt register key simply has no bundle row to match, so it is rejected by the same absence path
 * as a genuinely missing register, with no separate allow-list to keep in sync.
 */
const { isDeepStrictEqual } = require('util');
const { CODES, accepted, rejected } = require('./result');

// verifyRegisterRow(artifact, bundle) -> {verified, code, reason}. Fails closed on: a missing
// register/row field, a register key absent from bundle.registers, or a cited row whose content
// differs from the bundle's row in any field (an altered figure, a fabricated number, a dropped
// provenance field - all count as a mismatch; Rule 12 Gate 2's "exact re-match" ethos applied to
// structured data, not just prose).
function verifyRegisterRow(artifact, bundle) {
  if (typeof artifact.register !== 'string' || !artifact.register) {
    return rejected(CODES.REGISTER_ROW_MISSING_FIELDS, 'artifact.register is required');
  }
  if (!artifact.row || typeof artifact.row !== 'object' || Array.isArray(artifact.row)) {
    return rejected(CODES.REGISTER_ROW_MISSING_FIELDS, 'artifact.row is required (the exact row object the candidate cites)');
  }
  const registers = (bundle && bundle.registers) || {};
  const actual = registers[artifact.register];
  if (!actual || typeof actual !== 'object') {
    return rejected(CODES.REGISTER_ROW_ABSENT, 'bundle.registers has no row for ' + JSON.stringify(artifact.register));
  }
  if (!isDeepStrictEqual(actual, artifact.row)) {
    return rejected(
      CODES.REGISTER_ROW_MISMATCH,
      'the cited row does not exactly match bundle.registers.' + artifact.register
    );
  }
  return accepted(CODES.REGISTER_ROW_VERIFIED, 'row exact-matched bundle.registers.' + artifact.register);
}

module.exports = { verifyRegisterRow };

'use strict';
/**
 * breach/verifiers/coverage-proof.js - verifies a `coverage_proof` artifact: the artifact class for
 * ABSENCE claims ("no complaints procedure was found", "no cookie banner present"). Constitution
 * Rule 3 lists a verbatim quote, a network event and a register row as artifacts for something
 * PRESENT; an absence claim has no quote to point at by definition, so its deterministic artifact is
 * proof that the relevant surface was actually, sufficiently crawled (caution.md C-029: coverage as
 * BLOCKING data, not reporting theatre; C-037: every fabrication-prone absence is gated behind a real
 * live-read guard).
 *
 * Contract (candidate.artifact when type === 'coverage_proof'):
 *   {
 *     type: 'coverage_proof',
 *     page_class,           // informational: which page-class the absence claim concerns
 *     coverage: {
 *       pages: [url, ...],   // the pages examined for this class; MUST be non-empty
 *       tier1_fetched,       // true only if Tier-1 legal pages were fetched before any cap (C-026)
 *       truncated,           // must be false: a truncated corpus cannot honestly ground an absence
 *                            // claim (C-024/C-025 - russell-cooke's SRA string sat at char 11,080)
 *     },
 *   }
 *
 * This module never re-derives the coverage computation itself (that stays evidence/crawler/
 * coverage-contract.js's one door): it checks structural presence and cross-checks the claimed pages
 * against bundle.corpus.pages, so a coverage_proof cannot invent pages nobody actually crawled.
 */
const { CODES, accepted, rejected } = require('./result');

// bundlePageUrlSet(bundle) -> the Set of page URLs actually present on the bundle's corpus. Empty
// when the bundle carries no corpus at all (an unreachable/bot-walled bundle, caution.md C-038).
function bundlePageUrlSet(bundle) {
  const pages = bundle && bundle.corpus && Array.isArray(bundle.corpus.pages) ? bundle.corpus.pages : [];
  return new Set(pages.map((p) => p && p.url));
}

// verifyCoverageProof(artifact, bundle) -> {verified, code, reason}. Fails closed on: a missing
// coverage object, an empty/absent pages list, a claimed page not actually present in the bundle's
// corpus, tier1_fetched not literally true, or truncated not literally false.
function verifyCoverageProof(artifact, bundle) {
  const coverage = artifact.coverage;
  if (!coverage || typeof coverage !== 'object') {
    return rejected(CODES.COVERAGE_PROOF_MISSING_FIELDS, 'artifact.coverage is required');
  }
  if (!Array.isArray(coverage.pages) || coverage.pages.length === 0) {
    return rejected(CODES.COVERAGE_PROOF_NO_PAGES, 'artifact.coverage.pages must be a non-empty list of crawled page URLs');
  }
  const provenUrls = bundlePageUrlSet(bundle);
  const unproven = coverage.pages.filter((url) => !provenUrls.has(url));
  if (unproven.length > 0) {
    return rejected(
      CODES.COVERAGE_PROOF_PAGES_NOT_IN_BUNDLE,
      'coverage.pages lists page(s) absent from bundle.corpus.pages: ' + unproven.join(', ')
    );
  }
  if (coverage.tier1_fetched !== true) {
    return rejected(
      CODES.COVERAGE_PROOF_TIER1_NOT_FETCHED,
      'coverage.tier1_fetched must be true (C-026: Tier-1 legal pages fetched before any commercial page or cap)'
    );
  }
  if (coverage.truncated !== false) {
    return rejected(
      CODES.COVERAGE_PROOF_TRUNCATED,
      'coverage.truncated must be false (C-024/C-025: an absence claim on a truncated corpus is not provable)'
    );
  }
  return accepted(
    CODES.COVERAGE_PROOF_VERIFIED,
    'coverage report proves the surface was crawled: ' + coverage.pages.length + ' page(s), Tier-1 fetched, not truncated'
  );
}

module.exports = { verifyCoverageProof, bundlePageUrlSet };

#!/usr/bin/env node
'use strict';
/**
 * breach/verifiers/quote-match.js - THE constitutionally-named enforcement point for Rule 3 ("no
 * artifact, no breach") and Rule 12 Gate 2 ("verbatim-quote exact re-match"). Named explicitly in
 * CONSTITUTION.md (Rule 3, Rule 12 Gate 2, the Part III gate map) and in GAPS.md's `breach-artifact`
 * row as the planned gate for the whole no-artifact-no-breach class.
 *
 * This file is the ONLY path from a proposer's candidate to the adjudicator (breach/proposers/ and
 * breach/adjudicator/ are Wave-2 modules that do not exist yet; this directory is their shared
 * choke point, built first because Rule 3 is the enforcement point both sides must pass through).
 * It hosts the quote-artifact gate directly (Gate 2's specific, named concern) and dispatches the
 * other three artifact classes to their sibling modules:
 *
 *   quote artifact           -> verifyQuote (this file)
 *   network_event artifact   -> breach/verifiers/network-event.js
 *   register_row artifact    -> breach/verifiers/register-row.js
 *   coverage_proof artifact  -> breach/verifiers/coverage-proof.js
 *
 * ── the candidate/artifact contract (this module's own; breach/proposers/ must produce it) ────────
 *
 *   candidate = {
 *     rule_id: string,          // the catalogue rule this candidate proposes evidence for (pass
 *                                // through untouched; never read or judged by this directory)
 *     artifact: {
 *       type: 'quote' | 'network_event' | 'register_row' | 'coverage_proof',
 *       ... type-specific fields, see the sibling module or verifyQuote below ...
 *     },
 *   }
 *
 * A candidate with no artifact, or an artifact of an unrecognised type, is REJECTED, never passed
 * through (Rule 4: fail closed on malformed input). A verifier only ever narrows the candidate set;
 * it never creates, upgrades or edits a candidate (mirrors the adjudicator's filter-only contract,
 * Rule 11) - verifyAll wraps a reference to the ORIGINAL candidate object in a new result envelope
 * and never writes to the candidate itself.
 *
 * ── the ONE documented quote normalisation (Gate 2) ─────────────────────────────────────────────────
 *
 * Every run of whitespace characters (space, tab, newline, CR, form feed, vertical tab, and any
 * mixture of them) collapses to a single ASCII space. Nothing else: no case folding, no punctuation
 * stripping, no unicode normalisation, no trimming beyond what a whitespace-run collapse already does
 * at a string's edge. This is deliberately the SAME normalisation on both sides (the candidate's
 * quote and the bundle page's declared-surface text) and nothing more, because a second silent
 * transformation is exactly how Gate 2 could be weakened without anyone noticing: the whole point of
 * an "exact" re-match is that there is only one documented rule standing between "verified" and
 * "fabricated". Whitespace-only collapsing is necessary because the crawler's stripHtml()
 * (evidence/crawler/extract.js) turns block-level HTML boundaries into newlines while a proposer's
 * candidate quote is typically authored as a single line; without this one normalisation, a
 * genuinely-quoted sentence spanning a paragraph break would be rejected as a false mismatch. No
 * other drift (a changed word, a changed character, a re-cased letter) is tolerated: that is
 * precisely the class Gate 2 exists to catch (caution.md C-032 - models paraphrase inside quotation
 * marks).
 *
 * ── the detection-surface doctrine (caution.md C-035) ───────────────────────────────────────────────
 *
 * "Detection surface = evidence surface": a candidate declares which surface it detected the quote on
 * (`visible_text`, the stripped text every EvidenceBundle page carries per facts/README.md, or
 * `raw_html`, an optional richer surface some rules legitimately need per caution.md C-036's
 * trigger/mechanism asymmetry - e.g. proving a consent-manager script TAG is present, which stripHtml
 * deliberately removes from visible_text). This module matches the quote against EXACTLY the
 * declared surface and no other: a raw_html-only string can never satisfy a visible_text candidate,
 * and vice versa. The canonical EvidenceBundle.corpus.pages shape (facts/README.md) does not
 * currently carry a raw_html field - only evidence/crawler/'s own future work can add it - so a
 * raw_html candidate against a bundle page with no such field is honestly UNVERIFIABLE (rejected,
 * never assumed true).
 */
const { CODES, accepted, rejected } = require('./result');
const { verifyNetworkEvent } = require('./network-event');
const { verifyRegisterRow } = require('./register-row');
const { verifyCoverageProof } = require('./coverage-proof');

const VALID_SURFACES = new Set(['visible_text', 'raw_html']);

// normaliseWhitespace(s) -> s with every run of whitespace collapsed to a single space. THE one
// documented normalisation Gate 2 permits (see header). Applied identically to the candidate's quote
// and to the bundle page's declared-surface text before the exact-substring check.
function normaliseWhitespace(s) {
  return String(s == null ? '' : s).replace(/\s+/g, ' ');
}

// surfaceText(page, surface) -> the declared surface's text on this bundle page, or null when that
// surface is not present (an honest "cannot verify", never a silent fallback to the other surface).
function surfaceText(page, surface) {
  if (surface === 'visible_text') return typeof page.text === 'string' ? page.text : null;
  if (surface === 'raw_html') return typeof page.rawHtml === 'string' ? page.rawHtml : null;
  return null;
}

function findPage(bundle, pageUrl) {
  const pages = bundle && bundle.corpus && Array.isArray(bundle.corpus.pages) ? bundle.corpus.pages : [];
  return pages.find((p) => p && p.url === pageUrl) || null;
}

// verifyQuote(artifact, bundle) -> {verified, code, reason}. Gate 2 itself: fails closed on missing
// fields, an unrecognised surface, a page absent from the bundle, a declared surface absent from
// that page, or (after the one whitespace normalisation) a quote that is not an exact substring of
// the declared surface's text.
function verifyQuote(artifact, bundle) {
  if (typeof artifact.page_url !== 'string' || !artifact.page_url) {
    return rejected(CODES.QUOTE_MISSING_FIELDS, 'artifact.page_url is required');
  }
  if (typeof artifact.quote !== 'string' || !artifact.quote) {
    return rejected(CODES.QUOTE_MISSING_FIELDS, 'artifact.quote is required');
  }
  if (!VALID_SURFACES.has(artifact.surface)) {
    return rejected(
      CODES.QUOTE_INVALID_SURFACE,
      'artifact.surface must be "visible_text" or "raw_html", got ' + JSON.stringify(artifact.surface)
    );
  }
  const page = findPage(bundle, artifact.page_url);
  if (!page) {
    return rejected(CODES.QUOTE_PAGE_NOT_FOUND, 'no bundle page at ' + JSON.stringify(artifact.page_url));
  }
  const rawSurfaceText = surfaceText(page, artifact.surface);
  if (rawSurfaceText === null) {
    return rejected(
      CODES.QUOTE_SURFACE_UNAVAILABLE,
      'the "' + artifact.surface + '" surface is not present on this bundle page '
        + '(C-035: detection surface and evidence surface must be the same corpus)'
    );
  }
  const quoteNormalised = normaliseWhitespace(artifact.quote);
  if (!quoteNormalised) {
    return rejected(CODES.QUOTE_MISSING_FIELDS, 'artifact.quote is empty or whitespace-only after normalisation');
  }
  const surfaceNormalised = normaliseWhitespace(rawSurfaceText);
  if (!surfaceNormalised.includes(quoteNormalised)) {
    return rejected(
      CODES.QUOTE_MISMATCH,
      'quote does not exact-match (after whitespace-run normalisation) the "' + artifact.surface
        + '" surface of ' + JSON.stringify(artifact.page_url)
    );
  }
  return accepted(
    CODES.QUOTE_VERIFIED,
    'quote exact-matched the declared "' + artifact.surface + '" surface of ' + JSON.stringify(artifact.page_url)
  );
}

const VERIFIERS_BY_TYPE = {
  quote: verifyQuote,
  network_event: verifyNetworkEvent,
  register_row: verifyRegisterRow,
  coverage_proof: verifyCoverageProof,
};

// verifyCandidate(candidate, bundle) -> {verified, code, reason}. The fail-closed dispatcher: an
// unknown artifact.type is REJECTED, never passed through untested (Rule 4). Never mutates
// `candidate`.
function verifyCandidate(candidate, bundle) {
  if (!candidate || typeof candidate !== 'object') {
    return rejected(CODES.INVALID_CANDIDATE, 'candidate must be a non-null object');
  }
  const artifact = candidate.artifact;
  if (!artifact || typeof artifact !== 'object' || typeof artifact.type !== 'string' || !artifact.type) {
    return rejected(CODES.MISSING_ARTIFACT, 'candidate.artifact.type is required (Rule 3: no artifact, no breach)');
  }
  const verify = VERIFIERS_BY_TYPE[artifact.type];
  if (!verify) {
    return rejected(
      CODES.UNKNOWN_ARTIFACT_TYPE,
      'unrecognised artifact.type ' + JSON.stringify(artifact.type) + '; unknown artifact types fail closed, never pass through'
    );
  }
  return verify(artifact, bundle);
}

// verifyAll(candidates, bundle) -> {verified:[{candidate,verified,code,reason}], rejected:[...]}.
// Pure filter: every candidate is judged independently against the SAME bundle, the original
// candidate reference is carried unmodified in the result envelope, and nothing is ever dropped
// silently - a rejected entry always carries its code and reason.
function verifyAll(candidates, bundle) {
  const list = Array.isArray(candidates) ? candidates : [];
  const verified = [];
  const rejectedList = [];
  for (const candidate of list) {
    const result = verifyCandidate(candidate, bundle);
    const entry = { candidate, verified: result.verified, code: result.code, reason: result.reason };
    (result.verified ? verified : rejectedList).push(entry);
  }
  return { verified, rejected: rejectedList };
}

// ---------------------------------------------------------------------------------
// Calibration CLI (the earn-your-zero contract, eval/calibration-known-bad/run.js dialect; mirrors
// facts/identity.js and evidence/registers/registers.js's --calibrate convention exactly so a future
// CALIBRATIONS entry in eval/calibration-known-bad/run.js needs no adaptation).
// `node breach/verifiers/quote-match.js --calibrate [--json <path>]` runs every p3-verifier-*.json
// fixture under eval/calibration-known-bad/fixtures/ through verifyCandidate. Each fixture plants a
// candidate that must be REJECTED; a finding is emitted only when the rejection actually happens (and
// matches the fixture's expected_code, when given). Zero findings means this gate is broken.
// ---------------------------------------------------------------------------------
function runOneFixture(file, fixture) {
  const result = verifyCandidate(fixture.candidate, fixture.bundle);
  const poison = fixture.poison || {};
  const expectedCode = poison.expected_code;
  const caught = result.verified === false && (!expectedCode || result.code === expectedCode);
  if (!caught) return [];
  return [{
    file,
    line: 1,
    rule: 'p3-verifier-artifact-rejected',
    message: 'refused the poisoned candidate (' + result.code + '): ' + result.reason,
  }];
}

function runCalibration(fixturesDir) {
  const fs = require('fs');
  const path = require('path');
  const dir = fixturesDir || path.join(__dirname, '..', '..', 'eval', 'calibration-known-bad', 'fixtures');
  const findings = [];
  const files = fs.readdirSync(dir).filter((f) => /^p3-verifier-.*\.json$/.test(f)).sort();
  for (const f of files) {
    if (!/^[a-z0-9][a-z0-9.-]{0,251}$/i.test(f)) {
      throw new Error('unsafe path component: ' + JSON.stringify(f));
    }
    const abs = path.join(dir, f);
    const fixture = JSON.parse(fs.readFileSync(abs, 'utf8'));
    findings.push(...runOneFixture(abs, fixture));
  }
  return findings;
}

function calibrateMain(argv) {
  const fs = require('fs');
  const args = argv.slice(2);
  const jsonIdx = args.indexOf('--json');
  const jsonPath = jsonIdx !== -1 ? args[jsonIdx + 1] : null;
  const findings = runCalibration();
  if (jsonPath) fs.writeFileSync(jsonPath, JSON.stringify(findings, null, 2));
  process.stdout.write(JSON.stringify({ checker: 'breach-verifiers', findings }) + '\n');
  return 0;
}

if (require.main === module) {
  if (process.argv.includes('--calibrate')) {
    process.exit(calibrateMain(process.argv));
  } else {
    console.error('breach/verifiers/quote-match.js is a library. Only --calibrate is runnable from the CLI.');
    process.exit(2);
  }
}

module.exports = {
  verifyCandidate,
  verifyAll,
  verifyQuote,
  normaliseWhitespace,
  CODES,
  runCalibration,
  calibrateMain,
};

