65	const EVIDENCE_TYPES = Object.freeze(['presence', 'absence', 'behavioural', 'register']);
66	const SURFACES = Object.freeze(['visible_text', 'raw_html', 'footer', 'register_row', 'browser_lane']);
67	const PATTERN_KINDS = Object.freeze(['anchored-regex', 'token-set', 'url-path']);
68	
69	const MIN_TOKEN_LEN = 3;      // a token shorter than this is too generic to anchor a legal claim on
