234	// salientTokens(text) -> up to MAX_TOKENS distinctive content tokens (>= MIN_TOKEN_LEN, minus STOPWORDS),
235	// in first-seen order (deterministic). Digits-with-a-word like "18" are kept only when >= MIN_TOKEN_LEN
236	// so a bare short number never becomes a pattern.
237	function salientTokens(text) {
238	  const raw = String(text || '').toLowerCase().match(/[a-z0-9][a-z0-9'-]*[a-z0-9]|[a-z0-9]/g) || [];
