250	// patternsFromElement(elementText, evidenceType, pageClass) -> { patterns, unpatternable }. A quoted
251	// phrase becomes an anchored-regex (highest precision); otherwise a salient token-set; a findability
252	// element also yields a url-path from its page-class. An element that reduces to nothing distinctive is
253	// returned as unpatternable (propose.js abstains rather than fire a low-precision pattern - the C-049
254	// "mute or over-broad" trap avoided by refusing to guess).
255	function patternsFromElement(elementText, evidenceType, pageClass) {
256	  const guarded = evidenceType === 'absence';
257	  const patterns = [];
258	  for (const phrase of quotedSpans(elementText)) {
259	    const src = buildAnchoredRegex(phrase);
260	    if (src) patterns.push({ kind: 'anchored-regex', value: src, negation_guarded: guarded });
261	  }
262	  if (!patterns.length) {
263	    const tokens = salientTokens(elementText);
264	    if (tokens.length) {
265	      patterns.push({ kind: 'token-set', value: { tokens, mode: 'all' }, negation_guarded: guarded });
266	    }
267	  }
268	  if (pageClass && pageClass !== 'any' && FINDABILITY_RX.test(elementText)) {
