274	// dedupePatterns(patterns) -> patterns unique by (kind + normalised value), preserving order.
275	function dedupePatterns(patterns) {
276	  const seen = new Set();
277	  const out = [];
278	  for (const p of patterns) {
279	    const key = p.kind + '|' + (p.kind === 'token-set' ? (p.value.mode + ':' + p.value.tokens.join(',')) : p.value);
280	    if (seen.has(key)) continue;
281	    seen.add(key);
282	    out.push(p);
283	  }
284	  return out;
285	}
