const { verifyAll } = require(path.join(ENGINE, 'breach/verifiers/quote-match.js'));
const coverageContract = require(path.join(ENGINE, 'evidence/crawler/coverage-contract.js'));

// A minimal catalogue record with one 'absence' (prohibited content) obligation and one 'presence'
// (required content) obligation, so we exercise both evalPresenceBreach (-> quote artifact) and
