const catalogue = {
  records: [
    {
      id: 'TEST_PROHIBITED_CLAIM',
      website_obligations: [
        { evidence_type: 'absence', duty: 'must not claim "guaranteed results" anywhere on the site', elements: [] },
      ],
    },
    {
      id: 'TEST_REQUIRED_DISCLOSURE',
      website_obligations: [
        { evidence_type: 'presence', duty: 'must display the company registration number', elements: ['company number'] },
      ],
    },
  ],
};

