  domain: 'example.com',
  corpus: {
    pages: [
      { url: 'https://example.com/', title: 'Home', text: 'Welcome to our clinic. We offer excellent treatments for everyone.' },
      { url: 'https://example.com/results', title: 'Results', text: 'Our patients love us. We offer guaranteed results for all treatments, every time.' },
      { url: 'https://example.com/about', title: 'About', text: 'We have been serving the community for over 10 years with great care.' },
