// resolveQuoteArtifact(candidate, artifact) -> an effective quote artifact with real-proposer shape
// variance absorbed. Confirmed by direct integration probing against the landed breach/proposers/
// propose.js (evalPresenceBreach, this file's neighbour): it emits `artifact.text` rather than
// `artifact.quote`, and puts `page_url` on the CANDIDATE rather than on the artifact
// (`candidate(detectionSpec, KIND.PRESENCE_BREACH, {type:'quote', text, surface}, found.page_url, ...)`
// in propose.js). Both this module's originally-specified field names (artifact.page_url,
// artifact.quote) and propose.js's actual field names are accepted; an artifact-level field always
// wins when present, so nothing that already worked stops working - this only widens what verifyQuote
// can read. Only 'quote' artifacts are touched; every other type passes through unchanged. This is a
// narrow, additive compatibility seam, not a redesign of the artifact contract: it does not relax
// WHAT is verified (the exact-match check below is unchanged), only WHERE the same two facts (which
// page, what quote) may be read from on the way in.
function resolveQuoteArtifact(candidate, artifact) {
  if (!artifact || artifact.type !== 'quote') return artifact;
  const pageUrl = artifact.page_url == null ? (candidate && candidate.page_url) : artifact.page_url;
  const quote = artifact.quote == null ? artifact.text : artifact.quote;
  if (pageUrl === artifact.page_url && quote === artifact.quote) return artifact;
  return Object.assign({}, artifact, { page_url: pageUrl, quote });
}

// verifyCandidate(candidate, bundle) -> {verified, code, reason}. The fail-closed dispatcher: an
// unknown artifact.type is REJECTED, never passed through (Rule 4). Never mutates
// `candidate`.
function verifyCandidate(candidate, bundle) {
  if (!candidate || typeof candidate !== 'object') {
    return rejected(CODES.INVALID_CANDIDATE, 'candidate must be a non-null object');
  }
  const artifact = candidate.artifact;
  if (!artifact || typeof artifact !== 'object' || typeof artifact.type !== 'string' || !artifact.type) {
    return rejected(CODES.MISSING_ARTIFACT, 'candidate.artifact.type is required (Rule 3: no artifact, no breach)');
  }
  const verify = VERIFIERS_BY_TYPE[artifact.type];
  if (!verify) {
    return rejected(
      CODES.UNKNOWN_ARTIFACT_TYPE,
      'unrecognised artifact.type ' + JSON.stringify(artifact.type) + '; unknown artifact types fail closed, never pass through'
    );
  }
  return verify(resolveQuoteArtifact(candidate, artifact), bundle);
}

